import{U as e,gt as t,nt as n,rt as r}from"./chunks/framework.DwUqyNO4.js";var i=JSON.parse(`{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1783918682000}`),a={name:`architecture.md`};function o(e,i,a,o,s,c){return t(),n(`div`,null,[...i[0]||=[r(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to “Architecture”">​</a></h1><p>fontmin-rs is a Rust workspace with Node.js packaging. The goal is to keep expensive font parsing, subsetting, and conversion logic in Rust while exposing npm packages and TypeScript types for frontend ecosystems.</p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to “Directory Structure”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>crates/fontmin_core</code></td><td>Core models for font assets, formats, metadata, text</td></tr><tr><td><code>crates/fontmin_subset</code></td><td>TTF subsetting logic</td></tr><tr><td><code>crates/fontmin_woff</code></td><td>WOFF encoding and decoding</td></tr><tr><td><code>crates/fontmin_woff2</code></td><td>WOFF2 encoding, validation, and metadata inspection</td></tr><tr><td><code>crates/fontmin_eot</code></td><td>EOT encoding and decoding</td></tr><tr><td><code>crates/fontmin_svg</code></td><td>SVG font and SVG iconfont conversion</td></tr><tr><td><code>crates/fontmin_config</code></td><td>Shared serializable configuration and plugin model</td></tr><tr><td><code>crates/fontmin_fs</code></td><td>Shared filesystem helpers for path and glob handling</td></tr><tr><td><code>crates/fontmin_pipeline</code></td><td>Rust pipeline engine</td></tr><tr><td><code>crates/fontmin_testing</code></td><td>Shared Rust test fixtures and fixture constructors</td></tr><tr><td><code>apps/fontmin</code></td><td>Rust CLI application</td></tr><tr><td><code>napi/fontmin</code></td><td>N-API native binding</td></tr><tr><td><code>packages/fontmin</code></td><td>TypeScript package published to npm</td></tr><tr><td><code>npm/*</code></td><td>Platform-specific native binding package manifests</td></tr><tr><td><code>fixtures</code></td><td>Test fonts and fixed inputs</td></tr><tr><td><code>docs</code></td><td>VitePress documentation site</td></tr></tbody></table><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to “Data Flow”">​</a></h2><div class="language-mermaid line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  input[&quot;Font files&quot;] --&gt; detect[&quot;Format detection&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  detect --&gt; subset[&quot;Subset text/glyphs&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  subset --&gt; convert[&quot;Format conversion&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  convert --&gt; css[&quot;CSS generation&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  convert --&gt; write[&quot;Write assets&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  css --&gt; write</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>The CLI, Node API, and tests validate behavior around the same fixture set. In the TypeScript package, <code>optimize(config)</code> loads input files as assets, runs transforms in plugin order, then writes the final assets to <code>outDir</code>.</p><h2 id="package-boundaries" tabindex="-1">Package Boundaries <a class="header-anchor" href="#package-boundaries" aria-label="Permalink to “Package Boundaries”">​</a></h2><p>Rust crates stay focused: format detection, filesystem expansion, subsetting, conversion, diagnostics, and the pipeline live in separate crates. Shared test fixtures live in <code>fontmin_testing</code>, which is used only as a dev-dependency. The CLI, N-API binding, and browser WASM runtime reuse the same core capabilities while keeping test data consistent.</p><p>The TypeScript package is responsible for:</p><ul><li>Exposing public types.</li><li>Loading configuration files.</li><li>Expanding input files.</li><li>Orchestrating plugins.</li><li>Managing cache.</li><li>Providing the Fontmin-compatible migration layer.</li></ul><h2 id="current-limitations" tabindex="-1">Current Limitations <a class="header-anchor" href="#current-limitations" aria-label="Permalink to “Current Limitations”">​</a></h2><ul><li>OTF metadata inspection is supported. <code>otf2ttf</code> converts static CFF OTF fonts and default/explicit CFF2 instances to static TrueType <code>glyf</code> fonts, and rewrites glyf-backed OTF wrappers. The output drops CFF2 and variation tables.</li><li>WOFF2 inspect/validate checks headers and table directories, reads sfnt metadata tables, and supports WOFF2-to-TTF decode through the native path.</li><li><code>modernWeb()</code> only outputs WOFF, WOFF2, and CSS; EOT and SVG require explicit plugins or CLI formats.</li><li>Rust CLI module configs require Node.js 22+ and accept only serializable built-ins; arbitrary JavaScript hooks remain in the Node pipeline.</li></ul>`,13)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};